import React, { useState } from 'react';
import { toast } from 'react-toastify';
import { FaSyncAlt, FaDatabase, FaCheckCircle, FaTimesCircle, FaSpinner } from 'react-icons/fa';
import { syncAPI } from '../services/api';

function SyncDashboard() {
  const [syncing, setSyncing] = useState(false);
  const [syncResult, setSyncResult] = useState(null);

  const handleFullSync = async () => {
    setSyncing(true);
    setSyncResult(null);

    try {
      const response = await syncAPI.syncAll();
      setSyncResult(response.data);
      toast.success('Full sync completed successfully');
    } catch (error) {
      toast.error('Sync failed');
      console.error(error);
    } finally {
      setSyncing(false);
    }
  };

  return (
    <div>
      <div className="card">
        <div className="card-header">
          <h2>
            <FaSyncAlt style={{ marginRight: '8px' }} />
            System Synchronization
          </h2>
        </div>
        <div className="card-body">
          <div className="alert alert-info">
            <FaDatabase />
            <div>
              <strong>About Synchronization</strong>
              <p style={{ marginTop: '8px' }}>
                This tool synchronizes data from the HR System (SQL Server - HUMAN_2025) 
                to the Payroll System (MySQL - PAYROLL). This includes:
              </p>
              <ul style={{ marginTop: '8px', paddingLeft: '20px' }}>
                <li>Departments</li>
                <li>Positions</li>
                <li>Employee profiles</li>
              </ul>
            </div>
          </div>

          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(2, 1fr)', 
            gap: '24px', 
            marginTop: '24px',
            alignItems: 'center'
          }}>
            <div style={{ 
              padding: '24px', 
              background: '#ebf8ff', 
              borderRadius: '12px',
              textAlign: 'center'
            }}>
              <FaDatabase size={40} style={{ color: '#2b6cb0', marginBottom: '12px' }} />
              <h3>HR System</h3>
              <p style={{ color: '#4a5568', marginTop: '8px' }}>SQL Server - HUMAN_2025</p>
              <span className="badge badge-success" style={{ marginTop: '8px' }}>Source</span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'center' }}>
              {syncing ? (
                <FaSpinner size={32} style={{ color: '#3182ce', animation: 'spin 1s linear infinite' }} />
              ) : (
                <FaSyncAlt size={32} style={{ color: '#3182ce' }} />
              )}
            </div>

            <div style={{ 
              padding: '24px', 
              background: '#f0fff4', 
              borderRadius: '12px',
              textAlign: 'center',
              gridColumn: '2'
            }}>
              <FaDatabase size={40} style={{ color: '#276749', marginBottom: '12px' }} />
              <h3>Payroll System</h3>
              <p style={{ color: '#4a5568', marginTop: '8px' }}>MySQL - PAYROLL</p>
              <span className="badge badge-info" style={{ marginTop: '8px' }}>Target</span>
            </div>
          </div>

          <div style={{ textAlign: 'center', marginTop: '32px' }}>
            <button
              className="btn btn-primary"
              onClick={handleFullSync}
              disabled={syncing}
              style={{ padding: '16px 32px', fontSize: '1rem' }}
            >
              <FaSyncAlt />
              {syncing ? 'Synchronizing...' : 'Start Full Sync'}
            </button>
          </div>

          {syncResult && (
            <div style={{ marginTop: '32px' }}>
              <h3 style={{ marginBottom: '16px' }}>Sync Results</h3>
              <div className={`alert ${syncResult.success ? 'alert-success' : 'alert-danger'}`}>
                {syncResult.success ? <FaCheckCircle /> : <FaTimesCircle />}
                <span>{syncResult.message}</span>
              </div>

              <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', 
                gap: '16px',
                marginTop: '16px'
              }}>
                <div className="stat-card">
                  <div className="stat-card-value" style={{ color: '#2b6cb0' }}>
                    {syncResult.details?.departments_synced || 0}
                  </div>
                  <div className="stat-card-label">Departments Synced</div>
                </div>
                <div className="stat-card">
                  <div className="stat-card-value" style={{ color: '#805ad5' }}>
                    {syncResult.details?.positions_synced || 0}
                  </div>
                  <div className="stat-card-label">Positions Synced</div>
                </div>
                <div className="stat-card">
                  <div className="stat-card-value" style={{ color: '#38a169' }}>
                    {syncResult.details?.employees_synced || 0}
                  </div>
                  <div className="stat-card-label">Employees Synced</div>
                </div>
                <div className="stat-card">
                  <div className="stat-card-value" style={{ color: '#e53e3e' }}>
                    {syncResult.details?.employees_failed || 0}
                  </div>
                  <div className="stat-card-label">Employees Failed</div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default SyncDashboard;
